                        <div className="subticket-item" key={subticket.id}>
                          <button className="subticket-row" onClick={() => onOpenTicket(subticket.id)}>
                            <strong>{subticket.title}</strong>
                            <span>{statusName(board.columns, subticket.status)}</span>
                            {subticketBlockers.isBlocked && <span className="ticket-blocker-pill active">Blocked</span>}
                            {subticketBlockers.warnings.length > 0 && <span className="ticket-blocker-pill warning">Blocker Warning</span>}
                            <em className={clsx("priority", subticket.priority)}>{subticket.priority}</em>
                          </button>
                          <button
                            className="icon-button"
                            onClick={() => void unlinkChildTicket(subticket.id)}
                            disabled={subticketBusy}
                            aria-label={`Unlink ${subticket.title}`}
                          >
                            <X size={15} />
                          </button>
                        </div>
                      );
                    })
                  )}
                </div>
                {addTicketsOpen && (
                  <div className="add-subticket-panel">
                    <label className="field">
                      <span>New Subticket</span>
                      <input value={newSubticketTitle} onChange={(event) => setNewSubticketTitle(event.target.value)} placeholder="Subticket title" />
                    </label>
                    <div className="two-fields">
                      <label className="field">
                        <span>Priority</span>
                        <select value={newSubticketPriority} onChange={(event) => setNewSubticketPriority(event.target.value as TicketPriority)}>
                          {priorityOptions.map((option) => (
                            <option key={option}>{option}</option>
                          ))}
                        </select>
                      </label>
                      <label className="field">
                        <span>Labels</span>
                        <input value={newSubticketLabels} onChange={(event) => setNewSubticketLabels(event.target.value)} />
                      </label>
                    </div>
                    <button className="primary-button" onClick={() => void createChildTicket()} disabled={subticketBusy || newSubticketTitle.trim().length === 0}>
                      {subticketBusy ? <Loader2 className="spin" size={16} /> : <Plus size={16} />}
                      Create Subticket
                    </button>
                    <div className="link-existing-row">
                      <label className="field">
                        <span>Link Existing</span>
                        <select value={linkSubticketId} onChange={(event) => setLinkSubticketId(event.target.value)} disabled={linkableTickets.length === 0}>
                          <option value="">{linkableTickets.length === 0 ? "No available task tickets" : "Select a ticket"}</option>
                          {linkableTickets.map((candidate) => (
                            <option value={candidate.id} key={candidate.id}>
                              {ticketBlockerOptionLabel(candidate, board.tickets, board.columns)}
                            </option>
                          ))}
                        </select>
                      </label>
                      <button onClick={() => void linkExistingTicket()} disabled={subticketBusy || !linkSubticketId}>
                        <Plus size={16} />
                        Link
                      </button>
                    </div>
                  </div>
                )}
              </section>
            )}

            <ClarificationPanel
              questions={sidebarClarifications}
              answerDrafts={answerDrafts}
              submittingId={submittingAnswerId}
              onDraftChange={(questionId, answer) => setAnswerDrafts((current) => ({ ...current, [questionId]: answer }))}
              onSubmit={(questionId) => void submitClarificationAnswer(questionId)}
            />

            <AgentActivityPanel
              events={currentRunEvents}
              status={ticket.frontMatter.runStatus}
              runId={runId}
              runSummary={runSummary}
              logLoading={logLoading}
              logError={logError}
              onOpenLogs={() => setLogViewerOpen(true)}
              onRevealFile={() => void getRelayApi().ticket.revealFile(projectPath, ticketId)}
            />

            {!draftInProgress && (
              <div className="danger-row">
                <button onClick={duplicate}>
                  <Copy size={16} />
                  Duplicate
                </button>
                <button className="danger" onClick={remove}>
                  <Trash2 size={16} />
                  Delete
                </button>
              </div>
            )}
          </aside>
        </div>
      </aside>
      </div>
      {logViewerOpen && (
        <AgentLogViewer
          title={`${ticket.frontMatter.title} Logs`}
          events={currentRunEvents}
          loading={logLoading}
          error={logError}
          onClose={() => setLogViewerOpen(false)}
          onCopied={(kind) => setToast(copyToast(kind))}
          onCopyError={(error) => setToast({ kind: "error", message: error instanceof Error ? error.message : "Unable to copy." })}
        />
      )}
      {ticketUpdateLogViewerOpen && (
        <AgentLogViewer
          title={`${ticket.frontMatter.title} Ticket Update Logs`}
          events={ticketUpdateEvents}
          loading={false}
          error={null}
          onClose={() => setTicketUpdateLogViewerOpen(false)}
          onCopied={(kind) => setToast(copyToast(kind))}
          onCopyError={(error) => setToast({ kind: "error", message: error instanceof Error ? error.message : "Unable to copy." })}
        />
      )}
    </>
  );
}

export function App(): ReactElement {

import test from "node:test";
import assert from "node:assert/strict";
import { renderToStaticMarkup } from "react-dom/server";
import { AgentActivityPanel, AgentLogViewer, AgentProgressSummary } from "../src/renderer/src/components/AgentActivity";
import {
  agentEventLabel,
  agentEventText,
  agentEventTone,
  deriveAgentProgress,
  formatElapsedDuration
} from "../src/renderer/src/lib/agentProgress";
import type { RendererRunEvent } from "../src/shared/types";

const baseEvent = {
  projectPath: "/tmp/relay-project",
  ticketId: "tkt_1",
  runId: "run_1"
};

const event = (patch: Partial<RendererRunEvent> & { type: RendererRunEvent["type"]; timestamp: string }): RendererRunEvent =>
  ({
    ...baseEvent,
    ...patch
  }) as RendererRunEvent;

test("agent progress derives elapsed time and count metrics from run events", () => {
  const events: RendererRunEvent[] = [
    event({ type: "run.started", runId: "run_1", threadId: "thread_1", timestamp: "2026-05-11T10:00:00.000Z" }),
    event({ type: "file.change", path: "src/App.tsx", summary: "update src/App.tsx", timestamp: "2026-05-11T10:00:20.000Z" }),
    event({ type: "file.change", path: "src/App.tsx", summary: "update src/App.tsx", timestamp: "2026-05-11T10:00:30.000Z" }),
    event({ type: "web.search", query: "Codex SDK event types", timestamp: "2026-05-11T10:00:40.000Z" }),
    event({ type: "agent.message.delta", text: "Web search: legacy query", timestamp: "2026-05-11T10:00:45.000Z" }),
    event({ type: "run.completed", finalResponse: "Done.", timestamp: "2026-05-11T10:01:05.000Z" })
  ];

  const progress = deriveAgentProgress({ events, status: "completed", now: Date.parse("2026-05-11T10:02:00.000Z") });

  assert.equal(progress.elapsedLabel, "01:05");
  assert.equal(progress.filesEdited, 1);
  assert.equal(progress.webSearches, 2);
  assert.equal(progress.statusLabel, "Completed");
});

test("elapsed duration formatting stays stable across minute and hour boundaries", () => {
  assert.equal(formatElapsedDuration(null), "Unavailable");
  assert.equal(formatElapsedDuration(0), "00:00");
  assert.equal(formatElapsedDuration(61_000), "01:01");
  assert.equal(formatElapsedDuration(3_661_000), "1:01:01");
});

test("agent progress summary renders active elapsed state and unavailable metrics", () => {
  const markup = renderToStaticMarkup(
    <AgentProgressSummary
      events={[]}
      status="drafting"
      startedAt="2026-05-11T10:00:00.000Z"
      metricsAvailable={false}
      now={Date.parse("2026-05-11T10:01:01.000Z")}
    />
  );

  assert.match(markup, /Drafting/);
  assert.match(markup, /01:01/);
  assert.match(markup, /Files Edited/);
  assert.match(markup, /Unavailable/);
});

test("agent activity panel exposes a dedicated log entry point", () => {
  const markup = renderToStaticMarkup(
    <AgentActivityPanel
      events={[
        event({ type: "run.started", runId: "run_1", threadId: "thread_1", timestamp: "2026-05-11T10:00:00.000Z" })
