  min-height: 40px;
  border-bottom: 0;
  padding: 9px 11px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--relay-space-3);
}

.clarification-panel h3 {
  margin: 0;
  font-size: var(--relay-text-base);
  font-weight: 560;
}

.clarification-panel header span {
  color: var(--relay-text-subtle);
  font-size: var(--relay-text-sm);
}

.clarification-list {
  display: grid;
  gap: var(--relay-space-2);
  padding: var(--relay-space-3);
}

.clarification-card {
  border: 0;
  border-radius: var(--relay-radius-md);
  background: var(--relay-surface-2);
  padding: var(--relay-space-3);
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px rgb(255 255 255 / 4%);
}

.clarification-card.pending {
  background: var(--relay-warning-muted);
}

.clarification-card.answered {
  background: var(--relay-success-muted);
}

.clarification-question {
  display: grid;
  grid-template-columns: auto minmax(0, 1fr);
  gap: var(--relay-space-2);
  align-items: flex-start;
}

.clarification-question svg {
  margin-top: 2px;
  color: var(--relay-primary-text);
}

.clarification-question .markdown-block,
.clarification-answer .markdown-block {
  min-width: 0;
}

.clarification-question p,
.clarification-answer p {
  margin: 0;
  line-height: 1.45;
  overflow-wrap: anywhere;
}

.clarification-answer {
  margin-top: 10px;
  display: grid;
  gap: 4px;
}

.clarification-answer > span {
  color: var(--relay-success);
  font-size: var(--relay-text-sm);
  font-weight: 560;
}

.clarification-form {
  display: grid;
  gap: var(--relay-space-2);
  margin-top: 10px;
}

.clarification-form textarea {
  min-height: 84px;
}

.clarification-form button {
  justify-self: end;
}

.ticket-update-panel {
  margin-top: var(--relay-space-4);
  overflow: hidden;
  border: 0;
  border-radius: var(--relay-radius-md);
  background:
    linear-gradient(180deg, rgb(255 255 255 / 4%), transparent),
    var(--relay-surface);
  padding: var(--relay-space-3);
  display: grid;
  gap: var(--relay-space-3);
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px rgb(255 255 255 / 5%);
}

.ticket-update-panel header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--relay-space-3);
}

.ticket-update-panel h3 {
  margin: 0;
  font-size: var(--relay-text-base);
  font-weight: 560;
}

.ticket-update-input {
  min-height: 92px;
}

.ticket-update-actions {
  display: flex;
  align-items: center;
  gap: var(--relay-space-2);
  flex-wrap: wrap;
}

.ticket-update-error {
  border: 0;
  border-radius: var(--relay-radius-md);
  background: var(--relay-danger-muted);
  color: var(--relay-danger-text);
  padding: 9px 11px;
  display: flex;
  align-items: center;
  gap: var(--relay-space-2);
  font-size: var(--relay-text-md);
}

.ticket-update-error.warning {
  background: rgb(251 191 36 / 12%);
  color: #fbbf24;
}

.draft-loading-panel {
  margin-top: var(--relay-space-4);
  min-height: 240px;
  border-radius: var(--relay-radius-md);
  background:
    linear-gradient(180deg, rgb(255 255 255 / 5%), transparent),
    var(--relay-surface);
  color: var(--relay-text);
  display: grid;
  grid-template-columns: auto minmax(0, 1fr);
  align-items: center;
  gap: var(--relay-space-3);
  padding: var(--relay-space-4);
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px rgb(255 255 255 / 5%);
}

.draft-loading-panel h3 {
  margin: 0 0 4px;
  font-size: var(--relay-text-lg);
  font-weight: 580;
}

.draft-loading-panel p {
  margin: 0;
  color: var(--relay-text-muted);
  line-height: 1.45;
}

.detail-markdown {
  min-height: 360px;
}

.ticket-detail-primary .detail-markdown {
  min-height: min(52dvh, 560px);
}

.agent-activity-panel {
  margin-top: var(--relay-space-4);
  overflow: hidden;
  border: 0;
  border-radius: var(--relay-radius-md);
  background:
    linear-gradient(180deg, rgb(255 255 255 / 4%), transparent),
    var(--relay-surface);
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px rgb(255 255 255 / 5%);
}

.agent-activity-panel header {
  align-items: center;
  border-bottom: 0;
  padding: 9px 11px;
}

.agent-activity-panel h3 {
  font-size: var(--relay-text-base);
}

.agent-panel-actions {
  display: flex;
  align-items: center;
  gap: var(--relay-space-2);
  flex-wrap: wrap;
}

.agent-progress {
  margin-top: var(--relay-space-3);
  border: 0;
  border-radius: var(--relay-radius-md);
  background: rgb(255 255 255 / 3.5%);
  padding: var(--relay-space-3);
  display: grid;
  gap: var(--relay-space-3);
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px rgb(255 255 255 / 4%);
}

.agent-activity-panel .agent-progress {
  margin: 0;
  border: 0;
  border-radius: 0;
}

.ticket-detail-sidebar > .agent-activity-panel {
  overflow: visible;
  border-radius: 0;
  background: transparent;
  box-shadow: none;
}

.ticket-detail-sidebar > .agent-activity-panel header {
  padding: 0;
}

.ticket-detail-sidebar > .agent-activity-panel .agent-progress {
  border-radius: var(--relay-radius-md);
}

.agent-progress.active {
  background: var(--relay-warning-muted);
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px color-mix(in srgb, var(--relay-warning) 16%, transparent),
    0 0 34px rgb(231 195 106 / 5%);
}

.agent-progress.success {
  background: var(--relay-success-muted);
}

.agent-progress.warning {
  background: var(--relay-warning-muted);
}

.agent-progress.danger {
  background: var(--relay-danger-muted);
}

.agent-progress-main {
  display: grid;
  grid-template-columns: auto minmax(0, 1fr);
  align-items: center;
  gap: 10px;
}

.agent-progress-icon {
  width: 30px;
  height: 30px;
  border: 0;
  border-radius: var(--relay-radius-md);
  background: rgb(255 255 255 / 6%);
  color: var(--relay-primary-text);
  display: grid;
  place-items: center;
}

.agent-progress-main strong,
.agent-progress-main span {
  display: block;
}

.agent-progress-main strong {
  font-size: var(--relay-text-base);
  font-weight: 580;
}

.agent-progress-main span {
  margin-top: 2px;
  color: var(--relay-text-muted);
  font-size: var(--relay-text-md);
}

.agent-metrics {
  display: grid;
  grid-template-columns: repeat(3, minmax(116px, 1fr));
  gap: var(--relay-space-2);
}

.agent-metric {
  min-width: 0;
  border: 0;
  border-radius: var(--relay-radius-sm);
  background: rgb(255 255 255 / 4%);
  padding: 8px;
  display: grid;
  grid-template-columns: auto minmax(0, 1fr);
  gap: 4px 7px;
  align-items: center;
}

.agent-metric svg {
  color: var(--relay-text-subtle);
}

.agent-metric span {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  color: var(--relay-text-subtle);
  font-size: var(--relay-text-sm);
  font-weight: 520;
}

.agent-metric strong {
  grid-column: 1 / -1;
  color: var(--relay-text);
  font-size: var(--relay-text-lg);
  font-weight: 560;
  line-height: 1.1;
  font-variant-numeric: tabular-nums;
}

.agent-run-summary {
  display: grid;
  gap: var(--relay-space-2);
  padding: var(--relay-space-3);
  border-top: 1px solid rgb(255 255 255 / 5%);
  background: rgb(0 0 0 / 8%);
}

.agent-run-facts {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: var(--relay-space-2);
}

.agent-run-facts div,
.agent-usage-grid div {
  min-width: 0;
  display: grid;
  gap: 2px;
  border-radius: var(--relay-radius-sm);
  background: rgb(255 255 255 / 3.5%);
  padding: 8px;
}

.agent-run-facts span,
.agent-usage-grid span,
.agent-usage-title,
.agent-usage-unavailable {
  color: var(--relay-text-subtle);
  font-size: var(--relay-text-sm);
  font-weight: 540;
}

.agent-run-facts strong,
.agent-run-facts code,
.agent-usage-grid strong {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  color: var(--relay-text);
  font-size: var(--relay-text-md);
  font-weight: 560;
  font-variant-numeric: tabular-nums;
}

.agent-run-facts code {
  font-family: var(--relay-font-mono);
}

.agent-usage {
  display: grid;
  gap: var(--relay-space-2);
}

.agent-usage-title {
  display: flex;
  align-items: center;
  gap: 6px;
}

.agent-usage-grid {
  display: grid;
  grid-template-columns: repeat(5, minmax(0, 1fr));
  gap: var(--relay-space-2);
}

.agent-usage-unavailable {
  border-radius: var(--relay-radius-sm);
  background: rgb(255 255 255 / 3.5%);
  padding: 9px;
}

.agent-progress-foot,
.agent-recent-title,
.agent-inline-state {
  display: flex;
  align-items: center;
  gap: var(--relay-space-2);
  flex-wrap: wrap;
}

.agent-progress-foot {
  justify-content: space-between;
  color: var(--relay-text-subtle);
  font-size: var(--relay-text-sm);
}

.agent-recent {
  display: grid;
  gap: var(--relay-space-2);
  padding: var(--relay-space-3);
}

.agent-recent-title {
  justify-content: space-between;
  color: var(--relay-text-muted);
  font-size: var(--relay-text-sm);
  font-weight: 560;
}

.agent-inline-state {
  color: var(--relay-text-subtle);
  font-weight: 500;
}

.agent-state,
.agent-log-state {
  border: 0;
  border-radius: var(--relay-radius-md);
  color: var(--relay-text-subtle);
  padding: 10px 11px;
  font-size: var(--relay-text-md);
  background: rgb(255 255 255 / 3%);
  box-shadow: inset 0 0 0 1px rgb(255 255 255 / 4%);
}

.agent-state.error,
.agent-log-state.error {
  background: var(--relay-danger-muted);
  color: var(--relay-danger-text);
}

.agent-log-state.loading {
  display: flex;
  align-items: center;
  gap: var(--relay-space-2);
}

.agent-recent-list {
  display: grid;
  gap: var(--relay-space-1);
}

.agent-recent-row {
  display: grid;
  grid-template-columns: 64px 76px minmax(0, 1fr);
  gap: var(--relay-space-2);

  gap: var(--relay-space-2);
  align-items: baseline;
  border-top: 1px solid rgb(255 255 255 / 4%);
  padding-top: 7px;
}

.agent-recent-row span {
  color: var(--relay-text-subtle);
  font-size: var(--relay-text-sm);
  font-variant-numeric: tabular-nums;
}

.agent-recent-row strong {
  color: var(--relay-text-muted);
  font-size: var(--relay-text-sm);
}

.agent-recent-row p {
  margin: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  color: var(--relay-text-muted);
  font-family: var(--relay-font-mono);
  font-size: var(--relay-text-sm);
}

.agent-log-backdrop {
  z-index: 40;
}

.agent-log-modal {
  width: min(980px, calc(100vw - 64px));
  overflow: hidden;
  display: flex;
  flex-direction: column;
}

.agent-log-modal header {
  flex: 0 0 auto;
  padding-bottom: var(--relay-space-3);
  border-bottom: 0;
}

.agent-log-list {
  min-height: 0;
  max-height: min(680px, calc(100dvh - 190px));
  overflow: auto;
  margin: 0;
  padding: var(--relay-space-3) 0 0;
  list-style: none;
  display: grid;
  gap: var(--relay-space-2);
}

.agent-log-item {
  border: 0;
  border-radius: var(--relay-radius-md);
  background:
    linear-gradient(180deg, rgb(255 255 255 / 3.5%), transparent),
    var(--relay-surface);
  display: grid;
  grid-template-columns: 178px minmax(0, 1fr);
  overflow: hidden;
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px rgb(255 255 255 / 5%);
}

.agent-log-item.danger {
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px color-mix(in srgb, var(--relay-danger) 24%, transparent);
}

.agent-log-item.warning {
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px color-mix(in srgb, var(--relay-warning) 20%, transparent);
}

.agent-log-item.success {
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px color-mix(in srgb, var(--relay-success) 18%, transparent);
}

.agent-log-meta {
  border-right: 0;
  background: rgb(255 255 255 / 3.5%);
  padding: 9px;
  display: grid;
  gap: 6px;
  align-content: start;
}

.agent-log-meta time {
  color: var(--relay-text-muted);
  font-size: var(--relay-text-sm);
  font-variant-numeric: tabular-nums;
}

.agent-log-meta span {
  width: fit-content;
  min-height: 21px;
  border: 0;
  border-radius: 999px;
  background: rgb(255 255 255 / 5%);
  color: var(--relay-text-muted);
  padding: 3px 8px;
  font-size: var(--relay-text-sm);
  line-height: 1.2;
}

.agent-log-meta code {
  color: var(--relay-text-subtle);
  font-size: var(--relay-text-sm);
  white-space: normal;
  overflow-wrap: anywhere;
}

.agent-log-content {
  min-width: 0;
  padding: 10px 11px;
}

.agent-log-content pre {
  max-height: 360px;
  overflow: auto;
  margin: 0;
  white-space: pre-wrap;
  overflow-wrap: anywhere;
  color: var(--relay-text-muted);
  font-family: var(--relay-font-mono);
  font-size: var(--relay-text-sm);
  line-height: 1.45;
}

.agent-log-item.danger .agent-log-content pre {
  color: var(--relay-danger-text);
}

.agent-log-markdown {
  color: var(--relay-text-muted);
  font-size: var(--relay-text-sm);
}

.danger-row {
  margin-top: var(--relay-space-4);
  justify-content: space-between;
}

.danger {
  border-color: transparent;
  background: var(--relay-danger-muted);
  color: var(--relay-danger-text);
}

.danger:hover {
  background: color-mix(in srgb, var(--relay-danger) 19%, transparent);
}

.toast {
  position: fixed;
  left: 50%;
  bottom: 18px;
  z-index: 50;
  max-width: min(760px, calc(100vw - 32px));
  transform: translateX(-50%);
  border: 0;
  border-radius: var(--relay-radius-md);
  background:
    linear-gradient(180deg, rgb(255 255 255 / 7%), transparent),
    var(--relay-popover);
  color: var(--relay-text);
  padding: 10px 13px;
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px rgb(255 255 255 / 8%),
    var(--relay-shadow-panel);
  animation: toast-in 220ms var(--relay-spring) both;
}

.toast.error {
  background: color-mix(in srgb, var(--relay-popover) 84%, var(--relay-danger));
}

.toast.success {
  background: color-mix(in srgb, var(--relay-popover) 84%, var(--relay-success));
}

.empty-state {
  justify-content: center;
  align-items: center;
  text-align: center;
}

.empty-state h1 {
  margin: 0;
  font-size: 26px;
  font-weight: 580;
}

.empty-state p {
  margin: 10px 0 18px;
  color: var(--relay-text-subtle);
}

.preload-error {
  min-height: 100dvh;
  display: grid;
  place-content: center;
  gap: 10px;
  text-align: center;
  background: var(--relay-bg);
  color: var(--relay-text);
  padding: var(--relay-space-6);
}

.preload-error h1,
.preload-error p {
  margin: 0;
}

.preload-error p {
  color: var(--relay-text-subtle);
}

.spin {
  animation: spin 1s linear infinite;
}

@keyframes fade-in {
  from {
    opacity: 0;
  }
}

@keyframes surface-in {
  from {
    opacity: 0;
    transform: translateY(8px) scale(0.985);
  }
}

@keyframes panel-in {
  from {
    opacity: 0;
    transform: translateX(18px);
  }
}

@keyframes toast-in {
  from {
    opacity: 0;
    transform: translate(-50%, 8px) scale(0.985);
  }
}

@keyframes spin {
  to {
    transform: rotate(360deg);
  }
}

@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 1ms !important;
    animation-iteration-count: 1 !important;
    scroll-behavior: auto !important;
    transition-duration: 1ms !important;
  }
}

@media (max-width: 900px) {
  .app-shell {
    grid-template-columns: 238px minmax(0, 1fr);
  }

  .app-shell.chat-open {
    grid-template-columns: 238px minmax(0, 1fr) minmax(340px, 380px);
  }

  .topbar {
    flex-wrap: wrap;
    gap: var(--relay-space-3);
  }

  .topbar-project {
    flex-basis: 100%;
  }

  .topbar-actions {
    width: 100%;
    display: grid;
    grid-template-columns: minmax(180px, 1fr) max-content max-content max-content;
    align-items: center;
  }

  .search {
    width: auto;
    min-width: 0;
  }

  .board {
    grid-auto-columns: minmax(260px, 300px);
  }
}

@media (max-width: 860px) {
  .ticket-detail-backdrop {
    padding: 14px;
  }

  .detail-panel {
    height: calc(100dvh - 28px);
  }

  .ticket-detail-layout {
    grid-template-columns: 1fr;
    gap: var(--relay-space-4);
    overflow-y: auto;
    padding: 16px;
  }

  .ticket-detail-primary,
  .ticket-detail-sidebar {
    overflow: visible;
    padding-right: 0;
  }

  .ticket-detail-sidebar {
    padding-top: var(--relay-space-2);
    padding-bottom: 0;
  }

  .ticket-detail-primary .detail-markdown,
  .ticket-markdown-preview-panel.expanded {
    min-height: 420px;
  }
}

@media (max-width: 700px) {
  .app-shell {
    grid-template-columns: 1fr;
    grid-template-rows: auto minmax(0, 1fr);
  }

  .app-shell.chat-open,
  .app-shell.sidebar-collapsed.chat-open {
    grid-template-columns: 1fr;
  }

  .app-shell.sidebar-collapsed {
    grid-template-rows: minmax(0, 1fr);
  }

  .app-shell.sidebar-collapsed > .workspace {
    padding-left: 56px;
  }

  .sidebar-restore-button {
    top: 11px;
    left: 12px;
  }

  .sidebar {
    max-height: min(42dvh, 236px);
    border-right: 0;
    border-bottom: 0;
    padding: 12px;
    gap: var(--relay-space-2);
    box-shadow:
      inset 0 -1px 0 rgb(255 255 255 / 5%),
      var(--relay-inset-highlight);
  }

  .sidebar-list {
    flex-direction: row;
    flex: 1 1 auto;
    overflow-x: auto;
    overflow-y: hidden;
    padding: 0 0 2px;
    align-items: flex-start;
  }

  .project-group {
    min-width: 0;
    flex: 0 0 clamp(196px, 38vw, 232px);
  }

  .project-folder-row {
    min-width: 0;
  }

  .project-swimlane-list {
    max-height: 118px;
    margin-left: 28px;
    overflow-x: hidden;
    overflow-y: auto;
  }

  .sidebar-actions {
    margin-top: 0;
  }

  .workspace {
    padding: var(--relay-space-3);
  }

  .topbar {
    display: grid;
    grid-template-columns: minmax(0, 1fr);
    align-items: start;
    gap: var(--relay-space-3);
  }

  .topbar-actions {
    grid-template-columns: minmax(180px, 1fr) max-content max-content max-content;
    justify-content: stretch;
  }

  .board {
    grid-auto-columns: minmax(250px, calc(100vw - 28px));
  }

  .ticket-detail-backdrop {
    padding: 12px;
  }

  .detail-panel {
    height: calc(100dvh - 24px);
  }

  .ticket-detail-layout {
    padding: 14px;
  }

  .ticket-detail-modal-header {
    padding: 14px;
  }

  .repository-chat-panel {
    position: fixed;
    inset: 0;
    z-index: 24;
    width: auto;
    height: auto;
    min-width: 0;
    border-left: 0;
  }

  .modal {
    width: calc(100vw - 24px);
    max-height: calc(100dvh - 24px);
    padding: 16px;
  }

  .modal-grid,
  .create-fields,
  .create-manual-fields,
  .two-fields {
    grid-template-columns: 1fr;
  }

  .status-rail {
    right: 10px;
    bottom: 10px;
    left: 10px;
  }

  .codex-status {
    width: 100%;
  }
}

@media (max-width: 520px) {
  button {
    padding-inline: 10px;
  }

  .topbar-actions,
  .draft-actions,
  .modal-footer,
  .detail-actions,
  .ticket-update-actions,
  .agent-panel-actions,
  .danger-row {
    display: grid;
    grid-template-columns: 1fr;
